import{f as a,o as r,c as e,a2 as o}from"./chunks/framework.DHYrF-q6.js";const b=JSON.parse('{"title":"分布式事务","description":"","frontmatter":{"title":"分布式事务","outline":[2,3]},"headers":[],"relativePath":"middleware/distributed-system/transaction.md","filePath":"middleware/distributed-system/transaction.md","lastUpdated":1780747276000}'),d={name:"middleware/distributed-system/transaction.md"};function n(s,t,i,l,h,c){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to &quot;分布式事务&quot;">​</a></h1><blockquote><p>内容完善中，此页面将持续更新。</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>分布式事务是指在分布式系统中，一个业务操作需要跨越多个独立的服务或数据库，且需要保证这些操作要么全部成功，要么全部失败，以维持数据一致性。</p><h2 id="核心方案概览" tabindex="-1">核心方案概览 <a class="header-anchor" href="#核心方案概览" aria-label="Permalink to &quot;核心方案概览&quot;">​</a></h2><h3 id="_2pc-两阶段提交" tabindex="-1">2PC（两阶段提交） <a class="header-anchor" href="#_2pc-两阶段提交" aria-label="Permalink to &quot;2PC（两阶段提交）&quot;">​</a></h3><p>两阶段提交（Two-Phase Commit）是实现分布式事务的经典协议，通过协调者（Coordinator）统一管理参与者（Participants）的提交或回滚。</p><ul><li><strong>阶段一（Prepare）</strong>：协调者向所有参与者询问是否可以提交事务。</li><li><strong>阶段二（Commit/Abort）</strong>：协调者根据投票结果决定提交或回滚。</li></ul><div class="warning custom-block"><p class="custom-block-title">核心缺陷</p><p>协调者单点故障时，已投 Yes 的参与者会被永久阻塞，无法知道最终是 Commit 还是 Abort。</p></div><h3 id="_3pc-三阶段提交" tabindex="-1">3PC（三阶段提交） <a class="header-anchor" href="#_3pc-三阶段提交" aria-label="Permalink to &quot;3PC（三阶段提交）&quot;">​</a></h3><p>在 2PC 的基础上增加了**预提交（PreCommit）**阶段，并引入超时机制，部分缓解了协调者单点故障导致的阻塞问题。</p><h3 id="tcc-try-confirm-cancel" tabindex="-1">TCC（Try-Confirm-Cancel） <a class="header-anchor" href="#tcc-try-confirm-cancel" aria-label="Permalink to &quot;TCC（Try-Confirm-Cancel）&quot;">​</a></h3><p>TCC 是一种柔性事务方案，将事务分为三个阶段：</p><table tabindex="0"><thead><tr><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Try</strong></td><td>资源预留和锁定，检查业务可行性</td></tr><tr><td><strong>Confirm</strong></td><td>确认执行业务操作，使用 Try 阶段预留的资源</td></tr><tr><td><strong>Cancel</strong></td><td>取消业务操作，释放 Try 阶段预留的资源</td></tr></tbody></table><p>TCC 适用于需要强隔离性的业务场景，如金融转账、库存扣减等。</p><h3 id="saga-模式" tabindex="-1">Saga 模式 <a class="header-anchor" href="#saga-模式" aria-label="Permalink to &quot;Saga 模式&quot;">​</a></h3><p>Saga 将长事务拆分为多个本地事务，每个本地事务都有对应的补偿操作。如果某个本地事务失败，则按逆序执行之前成功事务的补偿操作。</p><p><strong>两种协调模式</strong>：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>优缺点</th></tr></thead><tbody><tr><td><strong>编排（Choreography）</strong></td><td>各服务通过事件驱动自主协调</td><td>松耦合，但流程分散难以追踪</td></tr><tr><td><strong>控制（Orchestration）</strong></td><td>由 Saga 编排器统一调度</td><td>集中可控，但编排器成为单点</td></tr></tbody></table><h3 id="seata" tabindex="-1">Seata <a class="header-anchor" href="#seata" aria-label="Permalink to &quot;Seata&quot;">​</a></h3><p>Seata（Simple Extensible Autonomous Transaction Architecture）是阿里巴巴开源的分布式事务解决方案，提供 AT、TCC、Saga 和 XA 四种事务模式。</p><table tabindex="0"><thead><tr><th>模式</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>AT</strong></td><td>自动回滚，对业务无侵入</td><td>基于关系型数据库的微服务</td></tr><tr><td><strong>TCC</strong></td><td>手动定义 Try/Confirm/Cancel</td><td>对隔离性要求高的场景</td></tr><tr><td><strong>Saga</strong></td><td>长事务补偿</td><td>多服务长流程</td></tr><tr><td><strong>XA</strong></td><td>基于 XA 协议</td><td>需要强一致性的场景</td></tr></tbody></table><h2 id="选型考量" tabindex="-1">选型考量 <a class="header-anchor" href="#选型考量" aria-label="Permalink to &quot;选型考量&quot;">​</a></h2><p>选择分布式事务方案时，需要综合考虑以下因素：</p><ul><li><strong>一致性要求</strong>：强一致性还是最终一致性？</li><li><strong>性能要求</strong>：事务协调对吞吐量和延迟的影响？</li><li><strong>业务侵入性</strong>：是否需要大量修改业务代码？</li><li><strong>运维复杂度</strong>：分布式事务组件的部署和维护成本？</li></ul><div class="info custom-block"><p class="custom-block-title">更多内容完善中</p><p>本文档将逐步补充各方案的详细实现原理、代码示例和面试题解析。敬请期待。</p></div>',26)])])}const m=a(d,[["render",n]]);export{b as __pageData,m as default};
